sub handle_create {
    my ($q) = @_;

    my $username = $q->param('username') // '';
    my $password = $q->param('password') // '';

    $username =~ s/^\s+|\s+$//g;

    if ($username eq '' || $password eq '') {
        return render_msg('Missing username or password.');
    }

