    if (!$rv) {
        my $err = $dbh->errstr || 'Unknown error';
        $sth->finish;
        $dbh->disconnect;
        return render_msg("Create failed: $err");
    }

    $sth->finish;
    $dbh->disconnect;

    return render_msg('User created.');
